export class JobRunner {
  constructor(store, execute) {
    this.store = store;
    this.execute = execute;
  }

  async runNext() {
    const job = this.store.claim();
    if (!job) {
      return { status: 'idle' };
    }

    try {
      const result = await this.execute(job.payload);
      const accepted = this.store.complete(job.id, result);
      return {
        jobId: job.id,
        status: accepted ? 'succeeded' : 'ignored',
        result
      };
    } catch (error) {
      const accepted = this.store.fail(job.id, error);
      return {
        jobId: job.id,
        status: accepted ? 'queued' : 'ignored',
        error: error instanceof Error ? error.message : String(error)
      };
    }
  }
}

