import test from 'node:test';
import assert from 'node:assert/strict';

import { JobStore } from '../src/job-store.mjs';
import { JobRunner } from '../src/job-runner.mjs';
import { describeJobEvent } from '../src/job-events.mjs';

test('a claimed export completes normally', async () => {
  const store = new JobStore();
  store.enqueue('export-1', { format: 'csv' });

  const runner = new JobRunner(store, async (payload) => `${payload.format}:ready`);
  const outcome = await runner.runNext();

  assert.deepEqual(outcome, {
    jobId: 'export-1',
    status: 'succeeded',
    result: 'csv:ready'
  });
  assert.equal(store.get('export-1').status, 'succeeded');
  assert.equal(store.get('export-1').attempt, 1);
});

test('a failed export returns to the queue and can be retried', async () => {
  const store = new JobStore();
  store.enqueue('export-2', { format: 'pdf' });
  let calls = 0;

  const runner = new JobRunner(store, async () => {
    calls += 1;
    if (calls === 1) {
      throw new Error('renderer unavailable');
    }
    return 'pdf:ready';
  });

  assert.equal((await runner.runNext()).status, 'queued');
  assert.equal(store.get('export-2').lastError, 'renderer unavailable');
  assert.equal((await runner.runNext()).status, 'succeeded');
  assert.equal(store.get('export-2').attempt, 2);
});

test('job event descriptions include the current attempt', () => {
  assert.equal(
    describeJobEvent({ id: 'export-3', status: 'running', attempt: 4 }),
    'job:export-3:running:attempt-4'
  );
});
